import styled from "styled-components";

export const ScrollLanding = styled.a`
  width: 100vmax;
  display: flex;
  text-decoration: none;
  transition: opacity .3s;
  :active {
    color: currentColor;
    opacity: .5;
    /* animation-name: fadeOut;
    animation-duration: .3s; */
  }
  :visited {
    display: none;
    color: currentColor;
  }
`;

export const ScrollUp = styled.a`
  top: 0;
  display: flex;
  min-height: 50vh;
  min-width: 100vw;
  text-decoration: none;
  :active {
    color: currentColor;
  }
  :visited {
    color: currentColor;
  }
`;

export const ScrollDown = styled.a`
  bottom: 0;
  display: flex;
  min-height: 50vh;
  min-width: 100vw;
  text-decoration: none;
  :active {
    color: currentColor;
  }
  :visited {
    color: currentColor;
  }
`;
